using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");

            // Breaking change 1: EF Core 9 renamed the default discriminator JSON
            // property from "Discriminator" to "$type". Existing 500K documents use
            // "Discriminator", and direct SQL queries reference c.Discriminator.
            b.HasDiscriminator<string>("Discriminator")
             .HasValue<Product>("Product");

            // Breaking change 2: EF Core 9 changed the synthesized JSON "id" from
            // "{EntityType}|{key}" (e.g. "Product|123") to just "{key}" (e.g. "123").
            // Preserve the old format so existing documents remain accessible.
            b.Property<string>("__id")
             .HasValueGenerator<LegacyCosmosIdGenerator>();

            // Breaking change 3: HasIndex now throws on the Cosmos provider instead
            // of being silently ignored. Removed — configure indexing policy through
            // the Cosmos DB portal or ARM/Bicep templates instead.
        });
    }
}

